
UPDATE conteudos SET video_url = 'https://www.youtube.com/watch?v=nkGRTflHp8U', conteudo_texto = '<h2>Geologia do Petróleo</h2><p>Formação, migração e acumulação de hidrocarbonetos - base para exploração na Petrobras.</p><h3>🛢️ Origem do Petróleo</h3><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><p><strong>Teoria Orgânica (mais aceita):</strong></p><ul><li>Matéria orgânica (plâncton, algas) depositada em bacias sedimentares</li><li>Soterramento + pressão + temperatura + tempo geológico</li><li>Transformação: Querogênio → Petróleo/Gás</li></ul></div><h3>🔥 Janela de Geração</h3><div style=''background:#fff3cd;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#ffc107;''><th style=''padding:10px;border:1px solid #ddd;''>Temperatura</th><th style=''padding:10px;border:1px solid #ddd;''>Produto</th><th style=''padding:10px;border:1px solid #ddd;''>Profundidade</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''>< 60°C</td><td style=''padding:10px;border:1px solid #ddd;''>Querogênio (imatura)</td><td style=''padding:10px;border:1px solid #ddd;''>Rasa</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>60-120°C</strong></td><td style=''padding:10px;border:1px solid #ddd;''><strong>Óleo</strong></td><td style=''padding:10px;border:1px solid #ddd;''>2.000-4.000m</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''>120-150°C</td><td style=''padding:10px;border:1px solid #ddd;''>Gás úmido/condensado</td><td style=''padding:10px;border:1px solid #ddd;''>4.000-5.000m</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''>> 150°C</td><td style=''padding:10px;border:1px solid #ddd;''>Gás seco / destruição</td><td style=''padding:10px;border:1px solid #ddd;''>> 5.000m</td></tr></table></div><h3>📊 Sistema Petrolífero</h3><div style=''background:#f0f0f0;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#0066cc;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Elemento</th><th style=''padding:10px;border:1px solid #ddd;''>Função</th><th style=''padding:10px;border:1px solid #ddd;''>Exemplo</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Rocha Geradora</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Gera o petróleo</td><td style=''padding:10px;border:1px solid #ddd;''>Folhelhos ricos em matéria orgânica</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Rocha Reservatório</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Armazena o petróleo</td><td style=''padding:10px;border:1px solid #ddd;''>Arenitos, carbonatos porosos</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Rocha Selante</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Impede a fuga</td><td style=''padding:10px;border:1px solid #ddd;''>Folhelhos, evaporitos, sal</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Trapa/Armadilha</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Geometria que acumula</td><td style=''padding:10px;border:1px solid #ddd;''>Anticlinal, falha, domo de sal</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Migração</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Caminho do óleo</td><td style=''padding:10px;border:1px solid #ddd;''>Primária (expulsão) e Secundária</td></tr></table></div><h3>🇧🇷 Pré-Sal Brasileiro</h3><div style=''background:#d4edda;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #28a745;''><h4>Características</h4><ul><li><strong>Localização:</strong> Abaixo de 2.000m de camada de sal</li><li><strong>Profundidade total:</strong> 5.000 a 7.000m (lâmina d''água + sedimentos)</li><li><strong>Reservatório:</strong> Carbonatos microbianos (microbialitos)</li><li><strong>Óleo:</strong> Leve e de alta qualidade (28-30° API)</li><li><strong>Principais campos:</strong> Lula, Búzios, Tupi, Sapinhoá, Júpiter</li></ul></div><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #17a2b8;''><h4>💡 Dica para Prova</h4><p>O <strong>sal</strong> no pré-sal funciona como excelente <strong>rocha selante</strong>, impedindo que o petróleo escape. Por isso as acumulações são gigantes!</p></div>' WHERE titulo = 'Resumo: Geologia do Petróleo';

UPDATE conteudos SET video_url = 'https://www.youtube.com/watch?v=6Hg8cO4aTvQ', conteudo_texto = '<h2>Perfuração de Poços</h2><p>Técnicas de perfuração e completação de poços de petróleo e gás.</p><h3>🔧 Tipos de Perfuração</h3><div style=''display:flex;gap:15px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:200px;background:#d4edda;padding:15px;border-radius:8px;''><h4>🏝️ Onshore</h4><p>Em terra firme</p><ul><li>Sondas terrestres</li><li>Menor custo</li><li>Acesso mais fácil</li></ul></div><div style=''flex:1;min-width:200px;background:#d1ecf1;padding:15px;border-radius:8px;''><h4>🌊 Offshore</h4><p>No mar</p><ul><li>Plataformas fixas</li><li>Plataformas flutuantes</li><li>Navios-sonda</li></ul></div></div><h3>🏗️ Equipamentos de Perfuração</h3><div style=''background:#f0f0f0;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#0066cc;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Equipamento</th><th style=''padding:10px;border:1px solid #ddd;''>Função</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Broca</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Corta/tritura a rocha (tricônica, PDC)</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Coluna de Perfuração</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Transmite rotação e peso à broca</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Kelly / Top Drive</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Fornece rotação à coluna</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Mesa Rotativa</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Gira a coluna (sistema convencional)</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>BOP (Blowout Preventer)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Segurança - previne kicks e blowouts</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Fluido de Perfuração</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Refrigera, carrega cascalhos, estabiliza</td></tr></table></div><h3>💧 Fluido de Perfuração (Lama)</h3><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><h4>Funções Principais:</h4><ul><li>✅ Resfriar e lubrificar a broca</li><li>✅ Carregar cascalhos para superfície</li><li>✅ Estabilizar as paredes do poço</li><li>✅ Controlar pressão da formação</li><li>✅ Transmitir energia hidráulica</li></ul><h4>Tipos:</h4><p><strong>Base água</strong> (mais comum) | <strong>Base óleo</strong> (formações reativas) | <strong>Base sintética</strong> (ambientalmente melhor)</p></div><h3>🔩 Revestimento e Cimentação</h3><div style=''background:#fff3cd;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#ffc107;''><th style=''padding:10px;border:1px solid #ddd;''>Revestimento</th><th style=''padding:10px;border:1px solid #ddd;''>Função</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Condutor</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Isola formações superficiais</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Superfície</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Protege aquíferos, ancora BOP</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Intermediário</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Isola zonas problemáticas</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Produção</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Isola zona produtora</td></tr></table></div><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #17a2b8;''><h4>💡 Dica para Prova</h4><p>O <strong>BOP</strong> é o principal equipamento de segurança. Ele fecha o poço em emergências para evitar <strong>blowout</strong> (erupção descontrolada)!</p></div>' WHERE titulo = 'Resumo: Perfuração';

UPDATE conteudos SET video_url = 'https://www.youtube.com/watch?v=svXIkwUBMSk', conteudo_texto = '<h2>Produção de Petróleo</h2><p>Métodos de elevação e recuperação para extrair petróleo dos reservatórios.</p><h3>📊 Fases da Produção</h3><div style=''display:flex;gap:15px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:150px;background:#d4edda;padding:15px;border-radius:8px;text-align:center;''><strong>1️⃣ Surgência</strong><p>Pressão natural do reservatório</p></div><div style=''flex:1;min-width:150px;background:#fff3cd;padding:15px;border-radius:8px;text-align:center;''><strong>2️⃣ Elevação Artificial</strong><p>Quando pressão cai</p></div><div style=''flex:1;min-width:150px;background:#d1ecf1;padding:15px;border-radius:8px;text-align:center;''><strong>3️⃣ Recuperação Avançada</strong><p>Maximizar extração</p></div></div><h3>⬆️ Métodos de Elevação Artificial</h3><div style=''background:#f0f0f0;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#0066cc;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Método</th><th style=''padding:10px;border:1px solid #ddd;''>Como Funciona</th><th style=''padding:10px;border:1px solid #ddd;''>Aplicação</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Gas Lift</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Injeção de gás para reduzir densidade do fluido</td><td style=''padding:10px;border:1px solid #ddd;''>Offshore (muito usado Petrobras)</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>BCS (Bombeio Centrífugo)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Bomba elétrica submersa</td><td style=''padding:10px;border:1px solid #ddd;''>Alta vazão, offshore</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>BCP (Cavidades Progressivas)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Bomba de parafuso helicoidal</td><td style=''padding:10px;border:1px solid #ddd;''>Óleos viscosos</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>BM (Bombeio Mecânico)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Cavalo de pau + bomba de fundo</td><td style=''padding:10px;border:1px solid #ddd;''>Onshore, baixas vazões</td></tr></table></div><h3>🔄 Recuperação de Petróleo</h3><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#28a745;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Tipo</th><th style=''padding:10px;border:1px solid #ddd;''>Descrição</th><th style=''padding:10px;border:1px solid #ddd;''>FR (%)</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Primária</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Energia natural do reservatório</td><td style=''padding:10px;border:1px solid #ddd;''>5-15%</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Secundária</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Injeção de água ou gás</td><td style=''padding:10px;border:1px solid #ddd;''>+15-25%</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Terciária (EOR)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Métodos especiais (térmico, químico, CO₂)</td><td style=''padding:10px;border:1px solid #ddd;''>+5-15%</td></tr></table><p style=''margin-top:10px;''><em>FR = Fator de Recuperação</em></p></div><h3>🌊 Sistemas de Produção Offshore</h3><div style=''display:flex;flex-wrap:wrap;gap:10px;margin:15px 0;''><span style=''background:#007bff;color:white;padding:8px 12px;border-radius:20px;''>Plataforma Fixa</span><span style=''background:#28a745;color:white;padding:8px 12px;border-radius:20px;''>FPSO</span><span style=''background:#ffc107;color:black;padding:8px 12px;border-radius:20px;''>Semi-submersível</span><span style=''background:#dc3545;color:white;padding:8px 12px;border-radius:20px;''>TLP</span><span style=''background:#6f42c1;color:white;padding:8px 12px;border-radius:20px;''>SPAR</span></div><div style=''background:#d4edda;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #28a745;''><h4>🚢 FPSO (Floating Production Storage Offloading)</h4><p>Navio-plataforma que <strong>produz, processa e armazena</strong> petróleo. Muito usado no pré-sal brasileiro por operar em águas ultraprofundas!</p></div><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #17a2b8;''><h4>💡 Dica para Prova</h4><p>No pré-sal, os métodos mais usados são: <strong>Gas Lift</strong> e <strong>BCS</strong>. O FPSO é a unidade padrão de produção!</p></div>' WHERE titulo = 'Resumo: Produção de Petróleo';

UPDATE conteudos SET video_url = 'https://www.youtube.com/watch?v=pRnsvqRbpZw', conteudo_texto = '<h2>Processamento e Refino</h2><p>Tratamento e refino de petróleo para obter derivados de valor comercial.</p><h3>🏭 Etapas do Processamento</h3><div style=''display:flex;gap:15px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:150px;background:#e8f4f8;padding:15px;border-radius:8px;text-align:center;''><strong>1️⃣</strong><p>Separação Óleo/Gás/Água</p></div><div style=''flex:1;min-width:150px;background:#d4edda;padding:15px;border-radius:8px;text-align:center;''><strong>2️⃣</strong><p>Tratamento do Óleo</p></div><div style=''flex:1;min-width:150px;background:#fff3cd;padding:15px;border-radius:8px;text-align:center;''><strong>3️⃣</strong><p>Tratamento do Gás</p></div><div style=''flex:1;min-width:150px;background:#d1ecf1;padding:15px;border-radius:8px;text-align:center;''><strong>4️⃣</strong><p>Refino</p></div></div><h3>🔥 Processos de Refino</h3><div style=''background:#f0f0f0;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#0066cc;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Processo</th><th style=''padding:10px;border:1px solid #ddd;''>Tipo</th><th style=''padding:10px;border:1px solid #ddd;''>Objetivo</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Destilação Atmosférica</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Separação</td><td style=''padding:10px;border:1px solid #ddd;''>Separar frações por ponto de ebulição</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Destilação a Vácuo</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Separação</td><td style=''padding:10px;border:1px solid #ddd;''>Separar frações pesadas</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Craqueamento Catalítico (FCC)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Conversão</td><td style=''padding:10px;border:1px solid #ddd;''>Quebrar moléculas → gasolina</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Hidrocraqueamento</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Conversão</td><td style=''padding:10px;border:1px solid #ddd;''>Quebra com hidrogênio</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Reforma Catalítica</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Conversão</td><td style=''padding:10px;border:1px solid #ddd;''>Aumentar octanagem gasolina</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Hidrotratamento (HDT)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Tratamento</td><td style=''padding:10px;border:1px solid #ddd;''>Remover enxofre (dessulfurização)</td></tr></table></div><h3>⛽ Derivados do Petróleo</h3><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#28a745;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Derivado</th><th style=''padding:10px;border:1px solid #ddd;''>Aplicação</th><th style=''padding:10px;border:1px solid #ddd;''>Faixa Ebulição</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>GLP</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Gás de cozinha</td><td style=''padding:10px;border:1px solid #ddd;''>< 40°C</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Nafta</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Petroquímica, gasolina</td><td style=''padding:10px;border:1px solid #ddd;''>40-175°C</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Gasolina</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Combustível veicular</td><td style=''padding:10px;border:1px solid #ddd;''>40-175°C</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Querosene/QAV</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Aviação</td><td style=''padding:10px;border:1px solid #ddd;''>175-235°C</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Diesel</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Transporte pesado</td><td style=''padding:10px;border:1px solid #ddd;''>235-305°C</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Óleos Lubrificantes</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Lubrificação</td><td style=''padding:10px;border:1px solid #ddd;''>305-400°C</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Asfalto/Resíduo</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Pavimentação</td><td style=''padding:10px;border:1px solid #ddd;''>> 400°C</td></tr></table></div><h3>🏭 Refinarias Petrobras</h3><div style=''display:flex;flex-wrap:wrap;gap:10px;margin:15px 0;''><span style=''background:#007bff;color:white;padding:8px 12px;border-radius:20px;''>REPLAN (SP)</span><span style=''background:#28a745;color:white;padding:8px 12px;border-radius:20px;''>RLAM (BA)</span><span style=''background:#ffc107;color:black;padding:8px 12px;border-radius:20px;''>REDUC (RJ)</span><span style=''background:#dc3545;color:white;padding:8px 12px;border-radius:20px;''>REVAP (SP)</span><span style=''background:#6f42c1;color:white;padding:8px 12px;border-radius:20px;''>REFAP (RS)</span></div><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #17a2b8;''><h4>💡 Dica para Prova</h4><p>A <strong>destilação atmosférica</strong> é o processo PRIMÁRIO de refino. O <strong>FCC</strong> é o mais importante para produzir gasolina!</p></div>' WHERE titulo = 'Resumo: Processamento';

UPDATE conteudos SET video_url = 'https://www.youtube.com/watch?v=rdWN-8RoD_Q', conteudo_texto = '<h2>Engenharia de Reservatórios</h2><p>Caracterização e simulação de reservatórios de petróleo e gás.</p><h3>📊 Propriedades do Reservatório</h3><div style=''background:#f0f0f0;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#0066cc;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Propriedade</th><th style=''padding:10px;border:1px solid #ddd;''>Símbolo</th><th style=''padding:10px;border:1px solid #ddd;''>O que mede</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Porosidade</strong></td><td style=''padding:10px;border:1px solid #ddd;''>φ (phi)</td><td style=''padding:10px;border:1px solid #ddd;''>% de espaços vazios na rocha</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Permeabilidade</strong></td><td style=''padding:10px;border:1px solid #ddd;''>k (mD)</td><td style=''padding:10px;border:1px solid #ddd;''>Capacidade de fluxo de fluidos</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Saturação</strong></td><td style=''padding:10px;border:1px solid #ddd;''>S</td><td style=''padding:10px;border:1px solid #ddd;''>% de óleo, água ou gás nos poros</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Compressibilidade</strong></td><td style=''padding:10px;border:1px solid #ddd;''>c</td><td style=''padding:10px;border:1px solid #ddd;''>Variação de volume com pressão</td></tr></table></div><h3>🔢 Classificação de Porosidade</h3><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#28a745;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Qualidade</th><th style=''padding:10px;border:1px solid #ddd;''>Porosidade</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''>Desprezível</td><td style=''padding:10px;border:1px solid #ddd;''>< 5%</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''>Pobre</td><td style=''padding:10px;border:1px solid #ddd;''>5-10%</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''>Regular</td><td style=''padding:10px;border:1px solid #ddd;''>10-15%</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''>Boa</td><td style=''padding:10px;border:1px solid #ddd;''>15-20%</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Excelente</strong></td><td style=''padding:10px;border:1px solid #ddd;''>> 20%</td></tr></table></div><h3>⚖️ Mecanismos de Produção</h3><div style=''display:flex;gap:15px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:200px;background:#d4edda;padding:15px;border-radius:8px;''><h4>💧 Influxo de Água</h4><p>Aquífero empurra o óleo</p><p>FR: 35-75%</p></div><div style=''flex:1;min-width:200px;background:#fff3cd;padding:15px;border-radius:8px;''><h4>💨 Capa de Gás</h4><p>Gás expande e empurra</p><p>FR: 20-40%</p></div><div style=''flex:1;min-width:200px;background:#d1ecf1;padding:15px;border-radius:8px;''><h4>🫧 Gás em Solução</h4><p>Gás liberado empurra óleo</p><p>FR: 5-30%</p></div></div><h3>📈 Curva de Declínio</h3><div style=''background:#fff3cd;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #ffc107;''><p>Produção diminui ao longo do tempo. Tipos de declínio:</p><ul><li><strong>Exponencial:</strong> Taxa constante de declínio</li><li><strong>Hiperbólico:</strong> Declínio diminui com o tempo</li><li><strong>Harmônico:</strong> Caso especial do hiperbólico</li></ul></div><h3>💻 Simulação de Reservatórios</h3><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><h4>Etapas:</h4><ol><li><strong>Modelagem Geológica:</strong> Geometria e propriedades</li><li><strong>Inicialização:</strong> Distribuição de fluidos</li><li><strong>Histórico:</strong> Ajustar modelo aos dados reais</li><li><strong>Previsão:</strong> Simular cenários futuros</li></ol><h4>Softwares:</h4><p>Eclipse (Schlumberger), CMG, IMEX, Petrel</p></div><h3>📐 Cálculo de Reservas</h3><div style=''background:#d4edda;padding:20px;border-radius:8px;margin:15px 0;text-align:center;''><h4 style=''color:#28a745;''>VOIP = A × h × φ × (1 - Sw) / Bo</h4><p><strong>VOIP:</strong> Volume de óleo in place</p><p>A = Área | h = Espessura | φ = Porosidade | Sw = Saturação água | Bo = Fator volume</p></div><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #17a2b8;''><h4>💡 Dica para Prova</h4><p>Lembre: <strong>Porosidade</strong> = capacidade de ARMAZENAR | <strong>Permeabilidade</strong> = capacidade de FLUIR. São independentes!</p></div>' WHERE titulo = 'Resumo: Reservatórios';
